import { updateCustomer, getCustomer } from '@/account/api';
import { useCallback, useEffect, useState, useRef } from 'preact/hooks';
import { debounce } from '@adobe-commerce/elsie/lib';
import { UseSellerAssistedBuyingSettingsReturn } from '@/account/types';

interface RemoteShoppingAssistanceConfigs {
  shoppingAssistanceEnabled: boolean;
  shoppingAssistanceCheckboxTitle: string;
  shoppingAssistanceCheckboxTooltip: string;
}

export const useSellerAssistedBuyingSettings = (
  remoteShoppingAssistanceConfigs: RemoteShoppingAssistanceConfigs | null
): UseSellerAssistedBuyingSettingsReturn => {
  const [loading, setLoading] = useState<boolean>(true);
  const [
    isRemoteShoppingAssistanceAvailable,
    setIsRemoteShoppingAssistanceAvailable,
  ] = useState<boolean>(false);
  const [
    isRemoteShoppingAssistanceEnabled,
    setIsRemoteShoppingAssistanceEnabled,
  ] = useState<boolean>(false);
  const [isAlertDismissed, setIsAlertDismissed] = useState<boolean>(false);
  const [hasLoadedCustomerPreference, setHasLoadedCustomerPreference] =
    useState<boolean>(false);
  const hasUserInteracted = useRef(false);

  const debouncedUpdateCustomer = useRef(
    debounce((checked: boolean) => {
      updateCustomer({
        allowRemoteShoppingAssistance: checked,
      }).catch((error) => {
        console.error('Failed to update remote shopping assistance:', error);
        setIsRemoteShoppingAssistanceEnabled(!checked);
        setIsAlertDismissed(false);
      });
    }, 500)
  ).current;

  useEffect(() => {
    return () => {
      debouncedUpdateCustomer.cancel?.();
    };
  }, [debouncedUpdateCustomer]);

  useEffect(() => {
    const enabledLoginAsCustomer =
      remoteShoppingAssistanceConfigs?.shoppingAssistanceEnabled ?? false;

    setIsRemoteShoppingAssistanceAvailable(enabledLoginAsCustomer);
  }, [remoteShoppingAssistanceConfigs]);

  useEffect(() => {
    if (!remoteShoppingAssistanceConfigs) {
      setLoading(false);
      setHasLoadedCustomerPreference(false);
      return;
    }

    setLoading(true);

    getCustomer()
      .then((customer) => {
        const allowRemoteShoppingAssistance =
          customer.allowRemoteShoppingAssistance ?? false;

        if (!hasUserInteracted.current) {
          setIsRemoteShoppingAssistanceEnabled(allowRemoteShoppingAssistance);
          setIsAlertDismissed(false);
        }
        setHasLoadedCustomerPreference(true);
      })
      .catch((error) => {
        console.error('Failed to load remote shopping assistance:', error);
      })
      .finally(() => {
        setLoading(false);
      });
  }, [remoteShoppingAssistanceConfigs]);

  const handleCheckboxChange = useCallback(
    (checked: boolean) => {
      hasUserInteracted.current = true;
      setHasLoadedCustomerPreference(true);
      setIsRemoteShoppingAssistanceEnabled(checked);
      setIsAlertDismissed(false);
      debouncedUpdateCustomer(checked);
    },
    [debouncedUpdateCustomer]
  );

  const handleDismissAlert = useCallback(() => {
    setIsAlertDismissed(true);
  }, []);

  const showAlert =
    (!loading || hasUserInteracted.current) &&
    hasLoadedCustomerPreference &&
    isRemoteShoppingAssistanceAvailable &&
    !isRemoteShoppingAssistanceEnabled &&
    !isAlertDismissed;

  return {
    loading,
    isRemoteShoppingAssistanceAvailable,
    isRemoteShoppingAssistanceEnabled,
    showAlert,
    handleCheckboxChange,
    handleDismissAlert,
  };
};
