import { classes, Container } from '@adobe-commerce/elsie/lib';
import { useText } from '@adobe-commerce/elsie/i18n';
import { useSellerAssistedBuyingSettings } from '@/account/hooks/containers/useSellerAssistedBuyingSettings';
import { useGetStoreConfigs } from '@/account/hooks/containers/useGetStoreConfigs';
import { SellerAssistedBuyingSettingsProps } from '@/account/types';
import { SellerAssistedBuyingSettingsControl } from '@/account/components';

export const SellerAssistedBuyingSettings: Container<
  SellerAssistedBuyingSettingsProps
> = ({ className }) => {
  const translations = useText({
    checkboxLabel: 'Account.sellerAssistedBuyingSettings.checkboxLabel',
    checkboxTooltip: 'Account.sellerAssistedBuyingSettings.checkboxTooltip',
    alertMessage: 'Account.sellerAssistedBuyingSettings.alertMessage',
    featureDisabledMessage:
      'Account.sellerAssistedBuyingSettings.featureDisabledMessage',
  });

  const {
    loading: storeConfigLoading,
    remoteShoppingAssistanceConfigs,
  } = useGetStoreConfigs();

  const {
    loading,
    isRemoteShoppingAssistanceAvailable,
    isRemoteShoppingAssistanceEnabled,
    showAlert,
    handleCheckboxChange,
    handleDismissAlert,
  } = useSellerAssistedBuyingSettings(remoteShoppingAssistanceConfigs);

  return (
    <div
      className={classes([
        'account-seller-assisted-buying-settings',
        className,
      ])}
      data-testid="sellerAssistedBuyingSettingsId"
    >
      <SellerAssistedBuyingSettingsControl
        loading={storeConfigLoading || loading}
        isRemoteShoppingAssistanceEnabled={isRemoteShoppingAssistanceEnabled}
        showAlert={showAlert}
        checkboxLabel={
          remoteShoppingAssistanceConfigs?.shoppingAssistanceCheckboxTitle ||
          translations.checkboxLabel
        }
        checkboxTooltip={
          remoteShoppingAssistanceConfigs?.shoppingAssistanceCheckboxTooltip ??
          translations.checkboxTooltip
        }
        alertMessage={translations.alertMessage}
        featureDisabledMessage={translations.featureDisabledMessage}
        handleCheckboxChange={handleCheckboxChange}
        handleDismissAlert={handleDismissAlert}
        isRemoteShoppingAssistanceAvailable={
          isRemoteShoppingAssistanceAvailable
        }
      />
    </div>
  );
};
